properties.query:
// Sentinel has no native TVM table. If MDE→Sentinel streaming is enabled,
// `DeviceTvmSoftwareVulnerabilities` is available. Otherwise this UC has
// no Sentinel translation — track via Update / Heartbeat OS-version
// gaps as a coarse approximation.
DeviceTvmSoftwareVulnerabilities
| where TimeGenerated > ago(1d)
| where CveId in~ (__CVE_LIST__)
| join kind=inner (DeviceInfo | where TimeGenerated > ago(1d)) on DeviceId
| project DeviceName, OSPlatform, CveId,
          VulnerabilitySeverityLevel, RecommendedSecurityUpdate
| order by VulnerabilitySeverityLevel asc, DeviceName asc
